/**
 * GitHub Rate-Limit Tracker
 * Hook: PostToolUse (Bash)
 *
 * When a `gh` invocation hits a GitHub API rate limit, emit an
 * additionalContext reminder telling the model to STOP and wait for reset.
 * This is belt-and-suspenders on top of the skill-level guidance in
 * ork:github-operations, ork:create-pr, and ork:review-pr — agents can
 * ignore text guidance, but hook-injected context steers the next turn
 * deterministically.
 *
 * Detection signals (any one triggers):
 *   1. gh's native error text: "API rate limit exceeded"
 *   2. Secondary rate limit:   "You have exceeded a secondary rate limit"
 *   3. HTTP 403 paired with a rate-limit body phrase
 *   4. CC 2.1.116's Bash tool hint surfaced in tool result (loose match)
 *
 * Output: non-blocking additionalContext. Hook NEVER denies — it only
 * informs. The pretool sibling (gh-rate-limit-preempt, future) can deny
 * subsequent gh calls within the reset window.
 *
 * CC 2.1.9 additionalContext contract, CC 2.1.116 references.
 */

import type { HookInput, HookResult, HookContext } from '../../types.js';
import { outputSilentSuccess, outputWithContext, getField } from '../../lib/common.js';
import { NOOP_CTX } from '../../lib/context.js';

// =============================================================================
// Patterns
// =============================================================================

const PRIMARY_LIMIT = /API rate limit exceeded/i;
const SECONDARY_LIMIT = /exceeded a secondary rate limit/i;
const RATE_LIMIT_GENERIC = /rate limit|x-ratelimit-remaining:\s*0\b/i;
const HTTP_403 = /HTTP\/[0-9.]+\s+403|status:\s*403/i;

// Reset-time extraction (stable `gh` formats):
//   "will be reset at 2026-04-21 09:45:00 UTC"
//   "reset at: 2026-04-21T09:45:00Z"
const RESET_AT_PATTERN = /reset(?:\s+at)?:?\s*([0-9]{4}-[0-9]{2}-[0-9]{2}[T\s][0-9:]+\s*(?:UTC|Z)?)/i;

/**
 * Check whether a command string is a `gh` invocation.
 * Handles: `gh ...`, `/usr/bin/gh ...`, `env GH_TOKEN=… gh ...`.
 */
function isGhCommand(command: string): boolean {
  // Strip leading env var prefixes and absolute paths
  const stripped = command.replace(/^(?:[A-Z_][A-Z0-9_]*=\S+\s+)+/, '').trim();
  return /(?:^|\/)gh(?:\s|$)/.test(stripped);
}

/**
 * Scan tool output for rate-limit indicators.
 * Returns reason + optional reset timestamp, or null if clean.
 */
function detectRateLimit(output: string): { reason: string; resetAt?: string } | null {
  if (!output) return null;

  if (PRIMARY_LIMIT.test(output)) {
    const match = output.match(RESET_AT_PATTERN);
    return { reason: 'primary', resetAt: match?.[1] };
  }
  if (SECONDARY_LIMIT.test(output)) {
    return { reason: 'secondary' };
  }
  // Loose match: only flag if we see BOTH 403 AND rate-limit phrasing
  // (avoids false positives on unrelated 403s like permission errors)
  if (HTTP_403.test(output) && RATE_LIMIT_GENERIC.test(output)) {
    const match = output.match(RESET_AT_PATTERN);
    return { reason: 'http-403', resetAt: match?.[1] };
  }
  return null;
}

function buildContext(reason: string, resetAt?: string): string {
  const header = '[gh-rate-limit-tracker] GitHub API rate limit detected';
  const guidance = [
    '',
    '**Do not retry this `gh` command.**',
    '',
    reason === 'secondary'
      ? 'Secondary rate limits trigger on bursts of requests to the same endpoint within a short window. Even if a primary-limit reset timestamp is available, a secondary limit typically clears within 60 seconds without blocking you on the hourly quota.'
      : resetAt
        ? `The hourly limit resets at **${resetAt}**. Wait until that time before resuming \`gh\` calls.`
        : 'Check `gh api rate_limit` to determine the reset time, then wait for reset before resuming.',
    '',
    'If this call was part of a loop (`/loop 5m gh pr checks …` or similar), **stop the loop** — do not let it continue firing into the rate limit. Resume manually after reset, or replace with `gh api --paginate` / GraphQL if you genuinely need high throughput.',
    '',
    '(This context was injected by the PostToolUse hook `posttool/bash/gh-rate-limit-tracker`. Skill-level guidance: `ork:github-operations` Best Practice #3.)',
  ].join('\n');
  return `${header}${guidance}`;
}

// =============================================================================
// Main hook
// =============================================================================

export async function ghRateLimitTracker(
  input: HookInput,
  _ctx: HookContext = NOOP_CTX,
): Promise<HookResult> {
  // Safe nested access via getField helper (same pattern as pattern-extractor).
  const command = getField<string>(input, 'tool_input.command') || '';
  if (!command || !isGhCommand(command)) return outputSilentSuccess();

  const stdout = getField<string>(input, 'tool_response.stdout') || '';
  const stderr = getField<string>(input, 'tool_response.stderr') || '';
  const combined = `${stdout}\n${stderr}`;

  const hit = detectRateLimit(combined);
  if (!hit) return outputSilentSuccess();

  return outputWithContext(buildContext(hit.reason, hit.resetAt));
}

// Testing-only exports
export { detectRateLimit, isGhCommand, buildContext };
